import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { adminAPI } from '../api';
// ...
const usersRes = await adminAPI.getAllUsers();
const bookingsRes = await adminAPI.getAllBookings();

function AdminDashboard() {
    const [users, setUsers] = useState([]);
    const [bookings, setBookings] = useState([]);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        const token = localStorage.getItem('token');
        const headers = { Authorization: `Bearer ${token}` };
        const usersRes = await axios.get('http://localhost:5000/api/admin/users', { headers });
        const bookingsRes = await axios.get('http://localhost:5000/api/admin/bookings', { headers });
        setUsers(usersRes.data.data);
        setBookings(bookingsRes.data.data);
    };

    return (
        <div>
            <h1>Admin Dashboard</h1>
            <h2>All Users</h2>
            <ul>
                {users.map(u => <li key={u.ClientID}>{u.FirstName} {u.LastName} ({u.Email}) - {u.Role}</li>)}
            </ul>
            <h2>All Bookings</h2>
            {/* display bookings table */}
        </div>
    );
}

export default AdminDashboard;
